const item = $input.first().json;
const headers = item.headers || {};
const authHeader = headers.authorization || headers.Authorization;
if (!authHeader || !String(authHeader).toLowerCase().startsWith('bearer ')) {
  throw new Error('UNAUTHORIZED: missing bearer token');
}
const body = item.body || {};
const sessionId = body.sessionId || item.sessionId;
const chatInput = body.chatInput || item.chatInput;
if (!sessionId) throw new Error('sessionId is required');
if (!chatInput) throw new Error('chatInput is required');
return { authHeader, sessionId, chatInput };

const user = $input.first().json;
const auth = $('Auth Guard').first().json;
const userId = user && user.id;
if (!userId) throw new Error('UNAUTHORIZED: invalid token');
const company = user && user.user_metadata && user.user_metadata.company_name;
if (company !== 'universo_tintas') {
  throw new Error('FORBIDDEN: user does not belong to universo_tintas');
}
const prefix = `u_${userId}__`;
const sessionId = auth.sessionId;
if (!String(sessionId).startsWith(prefix)) {
  throw new Error('FORBIDDEN: session belongs to another user');
}
return { userId, prefix, sessionId, chatInput: auth.chatInput };
